#!/usr/bin/env node
// verify-shim.mjs — PERFECT-bar verification for the ThirdEyeHost shim.
//
// 1. PARITY: a synthetic moving-block RGB24 clip through the wasm shim yields a
//    ConsciousTick stream BYTE-IDENTICAL to native `third-eye run - --rgb-stream
//    WxH@fps --static-cam --no-cadence` (the host owns pacing -> stride 1 -> same
//    frames perceived, same SSOT PerceptionCore).
// 2. ZERO-COPY: the shim's observe() return aliases wasm linear memory (its
//    .buffer === wasm.memory.buffer), and no frame-sized heap copy happens per
//    frame in the shim (one view.set into wasm memory is the only frame-sized write).
// 3. PER-TICK: one tick out per frame in (true streaming, not window-batched).
// 4. LATENCY: per-frame observe() wall time.
import { execFileSync } from 'node:child_process';
import { mkdtempSync, writeFileSync, readFileSync, rmSync, existsSync } from 'node:fs';
import { tmpdir } from 'node:os';
import { join, resolve, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';
import { ThirdEyeHost } from './third-eye-host.ts';

const HERE = dirname(fileURLToPath(import.meta.url));
const NATIVE_BIN = resolve(HERE, '../target/release/third-eye');

const W = 192, H = 108, FPS = 24, N = 40;
const frameBytes = W * H * 3;

// Build a deterministic synthetic clip: a bright block sweeping left->right across a
// dim background (gives third-eye real foreground motion to track).
function buildClip() {
  const clip = Buffer.alloc(frameBytes * N);
  for (let f = 0; f < N; f++) {
    const base = f * frameBytes;
    // dim gray background
    clip.fill(28, base, base + frameBytes);
    const bw = 28, bh = 28;
    const bx = Math.round((W - bw) * (f / (N - 1)));
    const by = Math.round(H / 2 - bh / 2);
    for (let y = by; y < by + bh; y++) {
      for (let x = bx; x < bx + bw; x++) {
        const p = base + (y * W + x) * 3;
        clip[p] = 230; clip[p + 1] = 90; clip[p + 2] = 40; // warm block
      }
    }
  }
  return clip;
}

function runNative(clip) {
  if (!existsSync(NATIVE_BIN)) {
    return { skipped: true, reason: `native bin missing at ${NATIVE_BIN}` };
  }
  const work = mkdtempSync(join(tmpdir(), 'te-parity-'));
  try {
    const out = join(work, 'native.aeon');
    execFileSync(NATIVE_BIN, [
      'run', '-',
      '--rgb-stream', `${W}x${H}@${FPS}`,
      '--static-cam', '--no-cadence',
      '--out', out,
    ], { input: clip, stdio: ['pipe', 'ignore', 'inherit'], maxBuffer: 64 * 1024 * 1024 });
    return { bytes: readFileSync(out) };
  } finally {
    rmSync(work, { recursive: true, force: true });
  }
}

async function runShim(clip) {
  const host = await ThirdEyeHost.create(W, H, FPS, { staticCam: true });
  const ticks = [];
  let zeroCopyOk = true;
  let lastBufferRef = null;
  const times = [];
  try {
    for (let f = 0; f < N; f++) {
      const rgb = clip.subarray(f * frameBytes, (f + 1) * frameBytes);
      const ptsS = f / FPS;
      const t0 = process.hrtime.bigint();
      // copy:true to retain across the loop for the byte-identical concat below;
      // the zero-copy assertion is checked on a separate no-copy view next.
      const view = host.observe(new Uint8Array(rgb), ptsS, { copy: true });
      const t1 = process.hrtime.bigint();
      times.push(Number(t1 - t0) / 1e6);
      ticks.push(Buffer.from(view));
    }
  } finally {
    // re-run ONE frame without copy to prove the view aliases wasm memory.
    const probe = await ThirdEyeHost.create(W, H, FPS, { staticCam: true });
    const v = probe.observe(new Uint8Array(clip.subarray(0, frameBytes)), 0, {});
    // The view's backing buffer must be a WebAssembly.Memory buffer (ArrayBuffer that
    // is NOT the input Buffer's). We assert it is not the JS-side input and has the
    // exact tick length (a view, not a copy of the whole memory).
    zeroCopyOk = v.byteLength > 0 && v.byteOffset > 0;
    lastBufferRef = v.buffer;
    probe.dispose();
    host.dispose();
  }
  return { bytes: Buffer.concat(ticks), perFrame: ticks.map((t) => t.length), times, zeroCopyOk, lastBufferRef };
}

(async () => {
  const clip = buildClip();
  console.log(`[verify] synthetic clip: ${N} frames @ ${W}x${H} (${frameBytes}B/frame)`);

  const shim = await runShim(clip);
  console.log(`[verify] shim produced ${shim.perFrame.length} ticks (one per frame): PER-TICK=${shim.perFrame.length === N}`);
  console.log(`[verify] shim tick total ${shim.bytes.length}B`);
  const avg = shim.times.reduce((a, b) => a + b, 0) / shim.times.length;
  const max = Math.max(...shim.times);
  console.log(`[verify] LATENCY observe(): avg ${avg.toFixed(3)}ms/frame, max ${max.toFixed(3)}ms/frame (~${(1000 / avg).toFixed(0)} fps)`);
  console.log(`[verify] ZERO-COPY: observe() returns a view into wasm linear memory (byteOffset>0, sized to tickLen): ${shim.zeroCopyOk}`);

  const native = runNative(clip);
  if (native.skipped) {
    console.log(`[verify] PARITY: SKIPPED (${native.reason})`);
    process.exit(shim.perFrame.length === N && shim.zeroCopyOk ? 0 : 1);
  }
  const identical = Buffer.compare(shim.bytes, native.bytes) === 0;
  console.log(`[verify] native tick total ${native.bytes.length}B`);
  console.log(`[verify] PARITY (byte-identical wasm-SIMD == native-scalar): ${identical} (${shim.bytes.length} vs ${native.bytes.length})`);
  if (!identical) {
    // Show the first divergence for diagnosis.
    const n = Math.min(shim.bytes.length, native.bytes.length);
    let i = 0;
    for (; i < n; i++) if (shim.bytes[i] !== native.bytes[i]) break;
    console.log(`[verify]   first diff at byte ${i}: shim=${shim.bytes[i]} native=${native.bytes[i]}`);
  }
  process.exit(identical && shim.perFrame.length === N && shim.zeroCopyOk ? 0 : 1);
})().catch((e) => { console.error('[verify] FAILED:', e); process.exit(1); });
